// ─── Verificar si hoy es el día de envío correcto ───────────────────────
// Cron dispara Lun–Vie en días 13, 14, 15.
// Solo continuamos si hoy es el día ajustado del 15:
//   15 cae Sábado → enviamos el viernes 14
//   15 cae Domingo → enviamos el viernes 13
//   15 cae hábil  → enviamos el 15

const tz   = 'America/Bogota';
const now  = new Date(new Date().toLocaleString('en-US', { timeZone: tz }));
const hoy  = now.getDate();
const mes  = now.getMonth();    // 0-indexed
const anio = now.getFullYear();

const dia15 = new Date(anio, mes, 15);
const dow15 = dia15.getDay();   // 0 = Dom, 6 = Sáb

let diaEnvio;
if      (dow15 === 6) diaEnvio = 14;  // Sábado  → viernes 14
else if (dow15 === 0) diaEnvio = 13;  // Domingo → viernes 13
else                  diaEnvio = 15;  // Hábil   → 15

if (hoy !== diaEnvio) return [];  // No es el día → detener ejecución

return [{ json: { diaEnvio, mes: mes + 1, anio } }];

// ─── Preparar JSON payload para el py-worker ───────────────────────────
const fs = require('fs');

const code = fs.readFileSync('/data/compartido/grafica_asi_vamos_worker.py', 'utf8');
const item = $input.item.json;

const payload = {
  code,
  nombre_cliente: item.Cliente,
  ventas_2024:    parseFloat(item.ventas_2024) || 0,
  ventas_2025:    parseFloat(item.ventas_2025) || 0,
  ventas_2026:    parseFloat(item.ventas_2026) || 0
};

// Nombre único para evitar colisiones entre ejecuciones paralelas
const tempFile = `payload_${Date.now()}_${Math.random().toString(36).slice(2)}.json`;
fs.writeFileSync(`/data/compartido/${tempFile}`, JSON.stringify(payload));

return [{
  json: {
    tempFile,
    cliente:     item.Cliente,
    nit:         item.Nit,
    ventas_2024: item.ventas_2024,
    ventas_2025: item.ventas_2025,
    ventas_2026: item.ventas_2026
  }
}];

// ─── Parsear respuesta del worker y preparar imagen como binario ────────
const raw = $input.item.json;

let workerOut;
try {
  workerOut = JSON.parse(raw.stdout);
} catch (e) {
  throw new Error('No se pudo parsear la respuesta del worker. stdout: ' + raw.stdout);
}

if (!workerOut.success) {
  const prev = $('Preparar payload').item.json;
  throw new Error(`Worker falló para "${prev.cliente}": ${workerOut.error}`);
}

const prev = $('Preparar payload').item.json;
const nombreArchivo = `grafica_${prev.cliente.replace(/[^a-zA-Z0-9áéíóúÁÉÍÓÚñÑ]/g, '_')}.png`;

return [{
  json: {
    cliente: prev.cliente,
    nit:     prev.nit
  },
  binary: {
    grafica: {
      data:     workerOut.result,
      mimeType: 'image/png',
      fileName: nombreArchivo
    }
  }
}];
